module multi_8bit (
    input [7:0] A, 
    input [7:0] B, 
    output reg [15:0] product
);

reg [7:0] partial_product [0:7];
reg [15:0] accumulator;
integer i;

always @* begin
    for (i = 0; i < 8; i = i + 1) begin
        partial_product[i] = A & {8{B[i]}};
    end
end

always @* begin
    accumulator = 16'b0;
    for (i = 0; i < 8; i = i + 1) begin
        accumulator = accumulator + (partial_product[i] << i);
    end
end

always @* begin
    product = accumulator;
end
endmodule
